import { Link } from "react-router-dom";
import { useEffect, useState } from "react";
import API from "../services/api";

function MatchCard({ match }) {
  const [teamATopPlayer, setTeamATopPlayer] = useState(null);
  const [teamBTopPlayer, setTeamBTopPlayer] = useState(null);

  useEffect(() => {
    const fetchTopPlayers = async () => {
      try {
        const [playersA, playersB] = await Promise.all([
          API.get(`/players/team/${match.teamA}`),
          API.get(`/players/team/${match.teamB}`)
        ]);

        const topA = playersA.data.length > 0 
          ? playersA.data.reduce((prev, current) => 
              prev.runs > current.runs ? prev : current
            ) 
          : null;

        const topB = playersB.data.length > 0 
          ? playersB.data.reduce((prev, current) => 
              prev.runs > current.runs ? prev : current
            ) 
          : null;

        setTeamATopPlayer(topA);
        setTeamBTopPlayer(topB);
      } catch (error) {
        console.error("Error fetching players:", error);
      }
    };

    fetchTopPlayers();
  }, [match.teamA, match.teamB]);

  return (
    <div className="card match-card">
      <h4>{match.teamA} vs {match.teamB}</h4>
      <p className="score">{match.scoreA} | {match.scoreB}</p>
      <p>Status: <span style={{ color: match.status === 'Live' ? 'red' : '#666', fontWeight: 'bold' }}>{match.status}</span></p>

      <div className="match-card-players">
        {teamATopPlayer && (
          <div className="top-player">
            <p className="player-name">{teamATopPlayer.name}</p>
            <div className="player-mini-stats">
              <span>{teamATopPlayer.runs} runs</span>
              <span>SR: {teamATopPlayer.strikeRate.toFixed(1)}</span>
            </div>
          </div>
        )}
        {teamBTopPlayer && (
          <div className="top-player">
            <p className="player-name">{teamBTopPlayer.name}</p>
            <div className="player-mini-stats">
              <span>{teamBTopPlayer.runs} runs</span>
              <span>SR: {teamBTopPlayer.strikeRate.toFixed(1)}</span>
            </div>
          </div>
        )}
      </div>

      <Link to={`/matches/${match._id}`} className="button-link">View Full Details</Link>
    </div>
  );
}

export default MatchCard;
